type Result<T, E> =
  | { type: "ok"; value: T }
  | { type: "err"; error: E };

function parseJsonResult(jsonString: string): Result<any, string> {
  try {
    const parsed = JSON.parse(jsonString);
    return { type: "ok", value: parsed };
  } catch {
    return { type: "err", error: "Invalid JSON" };
  }
}

const result = parseJsonResult('{ "name": "Alice" }');

if (result.type === "ok") {
  console.log("Parsed data:", result.value);
} else {
  console.error("Error:", result.error);
}

class MyMeta(type):
    def __new__(cls, name, bases, dct):
        print(f'Creating class {name}')
        return super().__new__(cls, name, bases, dct)

class MyClass(metaclass=MyMeta):
    pass

# Output: Creating class MyClass

class UppercaseMeta(type):
    def __new__(cls, name, bases, dct):
        if not name[0].isupper():
            raise TypeError("Class name must start with an uppercase letter")
        return super().__new__(cls, name, bases, dct)

class CorrectName(metaclass=UppercaseMeta):
    pass

# class wrongName(metaclass=UppercaseMeta):
